@dataclass
class TOTPConfig:
    """Configuration for TOTP generation and validation."""
    digits: int = 6
    period: int = 30
    algorithm: str = "SHA1"
    secret_length: int = 32  # bytes, 256-bit secret
    issuer: str = "SecureMFA"
    # Window of time steps to check (before and after current)
    # A window of 1 means we check current, previous, and next time step
    validation_window: int = 1
    # Rate limiting: max attempts per window
    max_attempts: int = 5
    lockout_duration: int = 300  # seconds

    def __post_init__(self):
        if self.digits not in (6, 8):
            raise ValueError("TOTP digits must be 6 or 8")
        if self.period < 15 or self.period > 60:
            raise ValueError("TOTP period must be between 15 and 60 seconds")
        if self.algorithm not in ("SHA1", "SHA256", "SHA512"):
            raise ValueError("Algorithm must be SHA1, SHA256, or SHA512")
        if self.secret_length < 20:
            raise ValueError("Secret length must be at least 20 bytes (160 bits)")
        if self.validation_window < 0 or self.validation_window > 2:
            raise ValueError("Validation window must be 0, 1, or 2")
        if self.max_attempts < 1:
            raise ValueError("Max attempts must be at least 1")


@dataclass
class UserTOTPState:
    """Tracks per-user TOTP state for replay and rate-limit protection."""
    # Set of time steps that have already been successfully used
    used_time_steps: set = field(default_factory=set)
    # Rate limiting
    attempt_count: int = 0
    first_attempt_time: float = 0.0
    locked_until: float = 0.0


class TOTPManager:
    """
    Secure TOTP (Time-based One-Time Password) manager.
    
    Security features:
    - Cryptographically secure secret generation
    - Constant-time comparison to prevent timing attacks
    - Replay attack prevention (each time step can only be used once)
    - Rate limiting to prevent brute force attacks
    - Input validation on all user-controlled data
    - No secrets or codes logged
    """

    # Mapping of algorithm names to hashlib constructors
    _HASH_ALGORITHMS = {
        "SHA1": hashlib.sha1,
        "SHA256": hashlib.sha256,
        "SHA512": hashlib.sha512,
    }

    def __init__(self, config: Optional[TOTPConfig] = None):
        self.config = config or TOTPConfig()
        # Per-user state tracking for replay prevention and rate limiting
        # In production, this should be backed by a persistent, secure store
        self._user_states: dict[str, UserTOTPState] = {}

    def generate_secret(self) -> bytes:
        """
        Generate a cryptographically secure random secret.
        
        Returns:
            Raw secret bytes. Store encrypted, never in plaintext.
        """
        secret = secrets.token_bytes(self.config.secret_length)
        logger.info("Generated new TOTP secret (secret value not logged)")
        return secret

    def secret_to_base32(self, secret: bytes) -> str:
        """
        Encode secret as base32 for use with authenticator apps.
        
        Args:
            secret: Raw secret bytes.
            
        Returns:
            Base32-encoded string (without padding).
        """
        if not isinstance(secret, bytes) or len(secret) < 20:
            raise ValueError("Invalid secret: must be at least 20 bytes")
        return base64.b32encode(secret).decode('ascii').rstrip('=')

    def base32_to_secret(self, base32_secret: str) -> bytes:
        """
        Decode a base32-encoded secret back to bytes.
        
        Args:
            base32_secret: Base32-encoded secret string.
            
        Returns:
            Raw secret bytes.
        """
        if not isinstance(base32_secret, str):
            raise ValueError("Base32 secret must be a string")
        
        # Validate base32 characters only
        cleaned = base32_secret.upper().strip()
        if not re.match(r'^[A-Z2-7]+$', cleaned):
            raise ValueError("Invalid base32 characters in secret")
        
        # Add padding if necessary
        padding_needed = (8 - len(cleaned) % 8) % 8
        padded = cleaned + '=' * padding_needed
        
        try:
            decoded = base64.b32decode(padded)
        except Exception:
            raise ValueError("Failed to decode base32 secret")
        
        if len(decoded) < 20:
            raise ValueError("Decoded secret too short (minimum 160 bits)")
        
        return decoded

    def _get_hash_func(self):
        """Get the hash function for the configured algorithm."""
        return self._HASH_ALGORITHMS[self.config.algorithm]

    def _compute_hotp(self, secret: bytes, counter: int) -> str:
        """
        Compute HOTP value per RFC 4226.
        
        Args:
            secret: Raw secret bytes.
            counter: Counter value (for TOTP, this is the time step).
            
        Returns:
            OTP string of configured digit length.
        """
        if not isinstance(secret, bytes) or len(secret) < 20:
            raise ValueError("Invalid secret")
        if not isinstance(counter, int) or counter < 0:
            raise ValueError("Invalid counter")

        # Pack counter as 8-byte big-endian
        counter_bytes = struct.pack('>Q', counter)
        
        # Compute HMAC
        hash_func = self._get_hash_func()
        hmac_digest = hmac.new(secret, counter_bytes, hash_func).digest()
        
        # Dynamic truncation per RFC 4226
        offset = hmac_digest[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_digest[offset:offset + 4])[0]
        truncated &= 0x7FFFFFFF  # Remove sign bit
        
        # Generate OTP of configured length
        otp = truncated % (10 ** self.config.digits)
        return str(otp).zfill(self.config.digits)

    def _get_time_step(self, timestamp: Optional[float] = None) -> int:
        """
        Calculate the current time step.
        
        Args:
            timestamp: Unix timestamp. If None, uses current time.
            
        Returns:
            Integer time step.
        """
        if timestamp is None:
            timestamp = time.time()
        if not isinstance(timestamp, (int, float)) or timestamp < 0:
            raise ValueError("Invalid timestamp")
        return int(timestamp) // self.config.period

    def generate_totp(self, secret: bytes, timestamp: Optional[float] = None) -> str:
        """
        Generate a TOTP code for the current time.
        
        Args:
            secret: Raw secret bytes.
            timestamp: Optional Unix timestamp (defaults to current time).
            
        Returns:
            TOTP code string.
        """
        time_step = self._get_time_step(timestamp)
        return self._compute_hotp(secret, time_step)

    def _get_user_state(self, user_id: str) -> UserTOTPState:
        """Get or create user state for tracking."""
        if user_id not in self._user_states:
            self._user_states[user_id] = UserTOTPState()
        return self._user_states[user_id]

    def _check_rate_limit(self, user_id: str) -> bool:
        """
        Check if the user is rate-limited.
        
        Returns:
            True if the request is allowed, False if rate-limited.
        """
        state = self._get_user_state(user_id)
        now = time.time()
        
        # Check if user is locked out
        if state.locked_until > now:
            logger.warning(
                "TOTP validation blocked for user (locked out): user_id=%s",
                user_id
            )
            return False
        
        # Reset counter if outside the rate limit window
        if now - state.first_attempt_time > self.config.lockout_duration:
            state.attempt_count = 0
            state.first_attempt_time = now
        
        # Check attempt count
        if state.attempt_count >= self.config.max_attempts:
            state.locked_until = now + self.config.lockout_duration
            state.attempt_count = 0
            logger.warning(
                "TOTP rate limit exceeded, locking user: user_id=%s",
                user_id
            )
            return False
        
        # Record attempt
        if state.attempt_count == 0:
            state.first_attempt_time = now
        state.attempt_count += 1
        
        return True

    def validate_totp(
        self,
        user_id: str,
        secret: bytes,
        code: str,
        timestamp: Optional[float] = None,
    ) -> bool:
        """
        Validate a TOTP code with full security protections.
        
        Security measures:
        - Input validation
        - Constant-time comparison
        - Replay attack prevention
        - Rate limiting
        
        Args:
            user_id: Unique user identifier for state tracking.
            secret: Raw secret bytes for the user.
            code: The TOTP code to validate.
            timestamp: Optional Unix timestamp (defaults to current time).
            
        Returns:
            True if the code is valid, False otherwise.
        """
        # Input validation
        if not isinstance(user_id, str) or not user_id.strip():
            raise ValueError("Invalid user_id")
        
        if not isinstance(code, str):
            logger.info("TOTP validation failed: code is not a string, user_id=%s", user_id)
            return False
        
        # Strict validation: code must be exactly the right number of digits
        if not re.match(r'^\d{' + str(self.config.digits) + r'}$', code):
            logger.info("TOTP validation failed: invalid code format, user_id=%s", user_id)
            return False
        
        if not isinstance(secret, bytes) or len(secret) < 20:
            raise ValueError("Invalid secret")
        
        # Rate limiting check
        if not self._check_rate_limit(user_id):
            return False
        
        current_time_step = self._get_time_step(timestamp)
        state = self._get_user_state(user_id)
        
        # Clean up old used time steps (keep only recent ones)
        min_valid_step = current_time_step - self.config.validation_window - 10
        state.used_time_steps = {
            ts for ts in state.used_time_steps if ts >= min_valid_step
        }
        
        # Check current time step and allowed window
        for offset in range(-self.config.validation_window, self.config.validation_window + 1):
            check_step = current_time_step + offset
            
            # Skip already-used time steps (replay prevention)
            if check_step in state.used_time_steps:
                continue
            
            expected_code = self._compute_hotp(secret, check_step)
            
            # Constant-time comparison to prevent timing attacks
            if hmac.compare_digest(code.encode('ascii'), expected_code.encode('ascii')):
                # Mark this time step as used to prevent replay
                state.used_time_steps.add(check_step)
                # Reset rate limit on success
                state.attempt_count = 0
                logger.info("TOTP validation succeeded for user_id=%s", user_id)
                return True
        
        logger.info("TOTP validation failed: code mismatch, user_id=%s", user_id)
        return False

    def get_provisioning_uri(
        self,
        secret: bytes,
        account_name: str,
        issuer: Optional[str] = None,
    ) -> str:
        """
        Generate an otpauth:// URI for provisioning authenticator apps.
        
        Args:
            secret: Raw secret bytes.
            account_name: User's account name/email.
            issuer: Optional issuer name (defaults to config).
            
        Returns:
            otpauth:// URI string.
        """
        if not isinstance(account_name, str) or not account_name.strip():
            raise ValueError("Invalid account name")
        
        # Sanitize account name - allow alphanumeric, @, ., -, _
        if not re.match(r'^[a-zA-Z0-9@.\-_+]+$', account_name.strip()):
            raise ValueError("Account name contains invalid characters")
        
        if not isinstance(secret, bytes) or len(secret) < 20:
            raise ValueError("Invalid secret")
        
        issuer = issuer or self.config.issuer
        if not re.match(r'^[a-zA-Z0-9 .\-_]+$', issuer):
            raise ValueError("Issuer contains invalid characters")
        
        base32_secret = self.secret_to_base32(secret)
        
        label = f"{quote(issuer)}:{quote(account_name.strip())}"
        
        params = {
            "secret": base32_secret,
            "issuer": issuer,
            "algorithm": self.config.algorithm,
            "digits": str(self.config.digits),
            "period": str(self.config.period),
        }
        
        param_str = "&".join(f"{k}={quote(str(v))}" for k, v in params.items())
        
        return f"otpauth://totp/{label}?{param_str}"

    def generate_qr_code(
        self,
        secret: bytes,
        account_name: str,
        issuer: Optional[str] = None,
    ) -> Optional[bytes]:
        """
        Generate a QR code image (PNG) for the TOTP provisioning URI.
        
        Args:
            secret: Raw secret bytes.
            account_name: User's account name/email.
            issuer: Optional issuer name.
            
        Returns:
            PNG image bytes, or None if qrcode library is not available.
        """
        if not HAS_QRCODE:
            logger.warning("qrcode library not installed; cannot generate QR code")
            return None
        
        uri = self.get_provisioning_uri(secret, account_name, issuer)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        buffer = io.BytesIO()
        img.save(buffer, format="PNG")
        png_bytes = buffer.getvalue()
        buffer.close()
        
        logger.info("Generated QR code for account (secret not logged)")
        return png_bytes

    def setup_new_user(
        self,
        user_id: str,
        account_name: str,
        issuer: Optional[str] = None,
    ) -> Tuple[bytes, str, str, Optional[bytes]]:
        """
        Complete setup for a new user's TOTP.
        
        Args:
            user_id: Unique user identifier.
            account_name: User's account name/email.
            issuer: Optional issuer name.
            
        Returns:
            Tuple of (secret_bytes, base32_secret, provisioning_uri, qr_png_bytes).
            The secret_bytes should be stored encrypted in your database.
            The base32_secret can be shown to the user as a manual entry option.
        """
        if not isinstance(user_id, str) or not user_id.strip():
            raise ValueError("Invalid user_id")
        
        secret = self.generate_secret()
        base32_secret = self.secret_to_base32(secret)
        uri = self.get_provisioning_uri(secret, account_name, issuer)
        qr_png = self.generate_qr_code(secret, account_name, issuer)
        
        logger.info("TOTP setup completed for user_id=%s (secrets not logged)", user_id)
        
        return secret, base32_secret, uri, qr_png


